import redis
import hashlib
import json
from typing import Any, Dict, Optional

class SecureRedisClient:
    def __init__(self, host: str = 'localhost', port: int = 6379, db: int = 0, password: Optional[str] = None):
        self.redis_client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=True,
            socket_connect_timeout=5,
            socket_timeout=5
        )
        self.script_cache: Dict[str, str] = {}
    
    def _validate_script(self, lua_script: str) -> bool:
        """Validate Lua script for security"""
        dangerous_patterns = [
            'redis.call',
            'redis.pcall',
            'redis.register_function',
            'loadfile',
            'dofile',
            'os.',
            'io.',
            'package.'
        ]
        
        script_lower = lua_script.lower()
        for pattern in dangerous_patterns:
            if pattern in script_lower:
                return False
        return True
    
    def _sanitize_parameters(self, params: Dict[str, Any]) -> Dict[str, Any]:
        """Sanitize user parameters"""
        sanitized = {}
        for key, value in params.items():
            if isinstance(value, (str, int, float, bool, type(None))):
                sanitized[key] = value
            elif isinstance(value, (list, dict)):
                sanitized[key] = json.dumps(value)
            else:
                sanitized[key] = str(value)
        return sanitized
    
    def execute_lua_script(self, lua_script: str, keys: list = None, args: list = None) -> Any:
        """
        Execute Lua script with security validation
        """
        if not self._validate_script(lua_script):
            raise ValueError("Invalid Lua script detected")
        
        try:
            if keys is None:
                keys = []
            if args is None:
                args = []
            
            # Hash the script for caching
            script_hash = hashlib.sha256(lua_script.encode()).hexdigest()
            
            # Cache script if not exists
            if script_hash not in self.script_cache:
                self.script_cache[script_hash] = lua_script
            
            # Execute script
            result = self.redis_client.eval(lua_script, len(keys), *keys, *args)
            return result
            
        except redis.exceptions.RedisError as e:
            raise RuntimeError(f"Redis error: {str(e)}")
        except Exception as e:
            raise RuntimeError(f"Script execution error: {str(e)}")
    
    def execute_script_with_params(self, lua_script: str, params: Dict[str, Any]) -> Any:
        """
        Execute Lua script with user parameters
        """
        sanitized_params = self._sanitize_parameters(params)
        
        # Convert params to keys and args
        keys = []
        args = []
        
        for key, value in sanitized_params.items():
            if isinstance(value, list):
                keys.extend(value)
            elif isinstance(value, dict):
                args.extend([json.dumps(value)])
            else:
                args.append(str(value))
        
        return self.execute_lua_script(lua_script, keys, args)
    
    def get_script_cache_info(self) -> Dict[str, Any]:
        """Get script cache information"""
        return {
            'cached_scripts': len(self.script_cache),
            'script_hashes': list(self.script_cache.keys())
        }

